import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';

const Navbar = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const group = JSON.parse(localStorage.getItem('group') || 'null');

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('group');
    toast.success('Logged out successfully');
    navigate('/login');
  };

  return (
    <nav className="bg-blue-600 text-white shadow-lg">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16 items-center">
          <div className="flex items-center">
            <Link to="/" className="text-xl font-bold">
              🏫 Science Fair
            </Link>
            {token && group && (
              <span className="ml-4 text-sm bg-blue-500 px-3 py-1 rounded">
                {group.registration_code}
              </span>
            )}
          </div>
          
          <div className="flex items-center space-x-4">
            {token ? (
              <>
                <Link to="/dashboard" className="hover:bg-blue-700 px-3 py-2 rounded transition">
                  Dashboard
                </Link>
                <Link to="/submit-project" className="hover:bg-blue-700 px-3 py-2 rounded transition">
                  Submit Project
                </Link>
                <Link to="/admin" className="hover:bg-blue-700 px-3 py-2 rounded transition">
                  Admin
                </Link>
                <button
                  onClick={handleLogout}
                  className="bg-red-500 hover:bg-red-600 px-4 py-2 rounded transition"
                >
                  Logout
                </button>
              </>
            ) : (
              <>
                <Link to="/register" className="hover:bg-blue-700 px-3 py-2 rounded transition">
                  Register
                </Link>
                <Link to="/login" className="bg-white text-blue-600 hover:bg-gray-100 px-4 py-2 rounded transition">
                  Login
                </Link>
              </>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
